#' Population evaluation
#'
#' Evaluate the fitness (inverse of the loss function) of a set of collapsed
#' cluster-average spectra encoded by one or more solutions contained in a
#' population.
#'
#' @param pop A population of solutions as generated by \code{\link{pop_init}}.
#' @param spec Matrix of shape (`nfreq`, `nrep`).
#'
#' @return A vector of length `length(pop)` with the fitness values of each
#' member of the input population.
evaluate <- function(pop, spec) {
  popsize <- length(pop)
  fitness_values <- rep(0, popsize)
  for (i in seq_len(popsize)) {
    fitness_values[i] <- fitness(pop[[i]], spec)
  }
  return(fitness_values)
}

#' Fitness evaluation
#'
#' Evaluate the fitness of a single solution (represented by a matrix).
#'
#' @param ch A matrix valued solution of shape (`nclust`, `2 * nbands - 1`).
#' @param spec Matrix of shape (`nfreq`, `nrep`).
#'
#' @return Double; fitness value (inverse of loss function).
fitness <- function(ch, spec) {
  nclust <- dim(ch)[1]

  # assign time series to clusters and compute fitness accordingly
  labels <- apply(dist_mat(spec, ch), 1, which.min)
  if (length(unique(labels)) != nclust) {
    # penalize if there empty clusters
    return(1e-50)
  } else {
    # compute the loss function as usual
    return(1 / loss_function(ch, labels, spec))
  }
}

#' Loss function
#'
#' Evaluate the loss function (sum of within cluster sum of squares) for a
#' single solution.
#'
#' @param ch A matrix valued solution of shape (`nclust`, `2 * nbands - 1`).
#' @param labels A vector of labels that represent assignments of the spectra
#' in `spec` to clusters. The `k`th label represents the row in `ch` by which
#' to collapse the `k`th spectrum in `spec`.
#' @param spec Matrix of shape (`nfreq`, `nrep`).
#'
#' @return Double; loss function (used to compute fitness).
loss_function <- function(ch, labels, spec) {
  nclust <- dim(ch)[1]; nbands <- (dim(ch)[2] + 1) / 2
  nfreq <- dim(spec)[1]

  # set aside the endpoints from the solution
  endpoints_index <- ch[, 1:(nbands - 1), drop = FALSE]
  within_cluster_ss <- vector("double", nclust)
  for (j in 1:nclust) {
    # set aside cluster spectra and endpoints
    clust_spec <- spec[, labels == j, drop = FALSE]
    endpoints_index_clust <- endpoints_index[j, ]

    # get collapsed measures and widths in each band
    collapsed <- avg_collapsed_by_index(clust_spec, endpoints_index_clust)
    nfreq_per_band <- diff(c(1, endpoints_index_clust, nfreq + 1))

    # expand the collapsed measures and compute L2 distance
    center <- rep(collapsed, nfreq_per_band)
    within_cluster_ss[j] <- sum((clust_spec - center)^2) / (2 * (nfreq + 1))
  }
  return(sum(within_cluster_ss))
}

#' Distance matrix
#'
#' Return the distance matrix used for cluster assignment by computing the L2
#' distance between each replicate spectrum and each collapsed spectrum
#' encoded by `ch`.
#'
#' @param spec Matrix of shape (`nfreq`, `nrep`).
#' @param ch A matrix valued solution of shape (`nclust`, `2 * nbands - 1`).
#'
#' @return Matrix of shape (`nrep`, `nclust`) where the `(i, j)`th entry is
#' the L2 distance between the `i`th replicate spectrum and the collapsed
#' spectrum of the `j`th cluster.
dist_mat <- function(spec, ch) {
  nclust <- dim(ch)[1]; nbands <- (dim(ch)[2] + 1) / 2
  nfreq <- dim(spec)[1]; nrep <- dim(spec)[2]

  # separate out endpoints and collapsed measures
  endpoints_index <- ch[, 1:(nbands - 1), drop = FALSE]
  collapsed <- ch[, nbands:dim(ch)[2], drop = FALSE]

  # compute distance matrix
  dist <- matrix(nrow = nrep, ncol = nclust)
  for (j in seq_len(nclust)) {
    # set aside cluster endpoints and collapsed measures
    endpoints_index_clust <- endpoints_index[j, ]
    collapsed_clust <- collapsed[j, ]

    # get widths of each band and expand collapsed measures
    nfreq_per_band <- diff(c(1, endpoints_index_clust, nfreq + 1))
    center <- rep(collapsed_clust, nfreq_per_band)

    # compute L2 distance between each spectrum and the jth cluster
    dist[, j] <- colSums((spec - center)^2) / (2 * (nfreq + 1))
  }
  return(dist)
}
